import{_ as e,o as t,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F05_應收帳款品質與收款天數.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F05_應收帳款品質與收款天數.md"}'),i={name:"審計報告庫/財務審計/6239_力成/20260617/F05_應收帳款品質與收款天數.md"};function o(n,a,h,s,d,c){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="f05-應收帳款品質與收款天數-財務審計專家報告" tabindex="-1">F05: 應收帳款品質與收款天數 - 財務審計專家報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-財務審計專家報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>應收帳款 (AR) 的規模與週轉天數 (DSO) 變動為何？是否存在客戶拖欠或虛增營收風險？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DSO從50天拉長至67天（+34%），AR/營收比升至18.2%；但99.4%未逾期，惡化主因H2營收集中致年底AR偏高，非客戶信用惡化。</li><li><strong>風險評級</strong>：中（關注）</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>DSO：45天(2022)→51天(2023)→50天(2024)→67天(2025)，增幅顯著。AR總額（含關係人）從2024年158.9億增至2025年185.4億（+16.7%），增幅遠超營收成長（+2.2%）。但從帳齡明細看：2025年AR總帳面133.9億中未逾期133.1億（99.4%），逾期1-60天僅0.73億（0.55%），逾期超60天僅0.05億（0.04%），備抵損失率0.45%，無顯著呆帳風險。關係人AR從57.2億降至51.7億（-9.5%），非關係人AR從101.7億增至133.6億（+31.4%），成長集中於非關係人客戶。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="收款天數檢測" tabindex="-1">收款天數檢測 <a class="header-anchor" href="#收款天數檢測" aria-label="Permalink to &quot;收款天數檢測&quot;">​</a></h3><p>DSO從2024年50天跳升至2025年67天，增加17天。但營收季節性因素是重要考量：2025年營收集中在下半年（H2營收約413.8億，H1僅335.5億），Q4單季達214.1億為全年最高。因AR通常按年底時點數計算，下半年營收爆發使年底AR基期偏高，自然拉高DSO。按全年平均日營收計算（749.3億/365=2.05億/天），DSO若改採平均營收而非年底營收為基準，約65天仍偏高但可控。</p><h3 id="背離趨勢診斷" tabindex="-1">背離趨勢診斷 <a class="header-anchor" href="#背離趨勢診斷" aria-label="Permalink to &quot;背離趨勢診斷&quot;">​</a></h3><p>2025年AR成長31.4%（非關係人部分）與營收成長2.2%出現顯著背離。AR成長率/營收成長率=14.3倍，遠超1.5倍警戒線。但有兩項緩解因素：(1)客戶授信期間為30天至月結150天，收款週期落後營收認列，Q4營收創高自然墊高AR；(2)關聯企業AR減少（從572M→517M），顯示關係人管控得當。現金流量表顯示2025年AR增加31.4億（營運資金流出），與帳面趨勢一致。</p><h3 id="壞帳準備審查" tabindex="-1">壞帳準備審查 <a class="header-anchor" href="#壞帳準備審查" aria-label="Permalink to &quot;壞帳準備審查&quot;">​</a></h3><p>2025年備抵損失60.8M（帳面AR的0.45%），較2024年65.3M甚至略減。在AR總額增加31.4%的情況下備抵反降，需關注。但據附註揭露，備抵係按IFRS 9存續期間預期信用損失模型計算，考量客戶過往違約率、現時財務狀況及產業經濟。2025年實際沖銷僅4.5M（前年0），損失率極低。力成前三大客戶為信譽卓著廠商，備抵適足性無虞，但AR擴大而備抵未同步增加仍值得後續追蹤。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>DSO驟升的營運資金壓力</strong>：DSO增17天相當於積壓約35億營運資金，直接侵蝕CFO（215.7億→167.0億）。</li><li><strong>AR成長背離營收</strong>：AR+31.4%（非關係人+49.9%）遠超營收+2.2%，反映部分新客戶可能享90-150天優惠帳期。2026年DSO可能進一步惡化至70-75天。</li><li><strong>Kioxia的AR回收風險</strong>：關係人AR 51.7億無備抵損失，考量Kioxia 2024年虧損~2,700億日圓，付款週期可能拉長。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>AR帳齡極度健康</strong>：99.4%未逾期，備抵率僅0.45%。客戶為全球一線大廠，信評高、倒帳風險極低。</li><li><strong>營收成長將自然降低DSO</strong>：2026年若營收逐季成長（4-5月YoY+38.5~38.9%），年底DSO有望回落至55-60天。</li><li><strong>現金儲備充足</strong>：現金163.8億+短期投資24.4億，合計188.2億流動資金，35億積壓仍安全無虞。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>DSO惡化主因營收季節性集中致年底AR墊高。AR帳齡極健康、客戶品質高、現金充足，無虛增營收或呆帳風險。2026年需追蹤DSO是否回落至55-60天區間。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (receivable_check 6239)</li><li>原始數據：FinMind TaiwanStockBalanceSheet (AccountsReceivableNet)</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 33-34，應收帳款附註及帳齡表)</li><li>年報數據：2025_Q4_6239_合併.pdf (page 52，合約餘額含關係人AR)</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const b=e(i,[["render",o]]);export{u as __pageData,b as default};
